VALUES
  ('promotion-53250add-moex-00078', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '甲將其名下之土地出賣於乙，已收清價金，並交付該地，惟未辦理所有權移轉登記。嗣該地經丙 市政府依法徵收，其地價補償費由甲領取完畢。下列敘述何者正確？', '["乙得依不當得利之規定，向甲請求返還地價補償費", "因乙已占有該地，且已付清價金，丙應負通知乙領取地價補償費之義務", "乙得依關於不當得利之規定，請求甲返還其已付清之價金", "乙不得向甲請求交付其所受領之地價補償費"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00079', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '依民法規定，下列何者並非要物契約？', '["和解契約", "使用借貸", "消費借貸", "寄託契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00080', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '甲僱用乙擔任公司會計，甲得知乙擔任甲公司企業工會之理事長後非常不高興，遂無預警解僱乙， 並要求乙當天即完成工作交接、收拾個人物品，及交出識別證不准乙再進入公司。乙認為甲係違 法解僱，甲乙間之僱傭關係仍存在，乙仍欲提供勞務，並請求甲支付報酬。關於甲乙間之權利義 務關係，下列敘述何者錯誤？', '["甲既已解僱乙，乃預示拒絕受領之意思，故乙得以準備給付勞務之事情通知甲，以代提出", "若乙現實提出勞務給付，但甲仍拒絕受領，則乙得依民法第487條有關僱用人受領勞務遲延之 規定，請求甲給付報酬", "若乙現實提出勞務給付，甲雖拒絕受領，但仍給付報酬者，甲日後得請求乙補服勞務", "若甲因受領遲延而依乙之請求支付報酬時，乙轉向他處服勞務所取得之利益，甲得由報酬額內扣除之 13540 13740"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00081', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '下列關於人事保證之敘述，何者錯誤？', '["人事保證為不要式契約", "人事保證因保證人之死亡而消滅", "人事保證所保證之行為，限於將來之職務上行為所生之損害賠償責任", "人事保證為保證人與債權人之契約"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00082', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '下列關於普通地上權終止原因之敘述，何者正確？', '["定有期限之地上權，若地上權成立之目的已不存在，法院得因當事人之請求，斟酌地上權成立 目的、建築物或工作物種類、性質及利用狀況等，終止地上權", "未定有期限而有支付地租約定之地上權，地上權人若於一年前通知土地所有人，或支付未到期 之一年分地租後，地上權即當然終止", "地上權人未依約定之使用方法使用土地，經土地所有人阻止而仍繼續為之，若地上權經設定抵 押權者，土地所有人於經抵押權人同意後，始得終止地上權", "地租約定若經登記，於地上權讓與時，讓與人與受讓人積欠之地租，若併同計算已達二年總額， 經土地所有人定期催告仍未支付者，土地所有人得終止地上權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00083', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '甲提供其所有之不動產設定最高限額抵押權新臺幣1000萬元於乙，下列敘述何者錯誤？', '["原債權確定前，乙經甲同意，得將最高限額抵押權之一部單獨讓與丙，而乙、丙成為先、後次 序之抵押權人", "原債權確定前，乙經甲同意，得將丙加入成為該抵押權之共有人，乙、丙原則上按其債權額比 例分配價金", "受讓人丙為避免其最高限額抵押權無擔保債權存在而歸於確定，得與甲約定變更原擔保債權之 範圍或其債務人", "基於抵押權之從屬性，最高限額抵押權所擔保之原債權確定後，乙不得將最高限額抵押權單獨 讓與他人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00084', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '下列關於動產善意取得之敘述，何者錯誤？', '["受讓人若係明知或因重大過失而不知讓與人無讓與之權利者，不得主張動產所有權之善意取得", "動產占有之受讓，若係依占有改定方式為之者，須受讓人受現實交付且交付時善意為限，始受 占有法律規定之保護", "占有物如係盜贓，原占有人自喪失占有之時起二年內，得向善意受讓之現占有人請求回復其物， 並自請求時起，回復其原來之權利", "占有之盜贓、遺失物如係金錢或未記載權利人之有價證券，原占有人即不得向其善意受讓之現 占有人請求回復"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00085', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '下列何者因有違物權法定主義之規定，而不得辦理登記？', '["以共有之土地為共有人中之一人所設定之普通地上權", "以典權為標的物所設定之不動產質權", "以農育權為標的物所設定之權利抵押權", "以自己之不動產所設定之不動產役權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00086', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '下列何者非屬所有權取得時效之中斷事由？', '["占有人變為他主占有之意思占有", "占有人變為非和平或非公然占有", "占有人變為惡意或有過失占有", "所有權人依民法第767條規定訴請返還占有物"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL),
  ('promotion-53250add-moex-00087', 'promotion-53250add', 'promotion-53250add-moex-112-9b7ab1bb', 'sub-promotion-53250add-03', NULL, 'single_choice', '依民法第962條規定，占有被侵奪者，占有人得請求返還其占有物。下列何者非該條所定之主體？', '["無權占有人", "間接占有人", "直接占有人", "占有輔助人 13540 13740"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:46+00:00", "source_pdf_sha1": "0635b758199f", "answer_pdf_sha1": "cdba98d79113", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "137", "s": "0501", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "智慧財產行政"}'::jsonb, NULL)
